SELECT
    u.id, u.username, u.nickname, u.email, u.phone, u.avatar, u.gender, u.status,
    u.last_login_time, u.last_login_ip, u.dept_id, u.post_id, u.user_type,
    u.login_type, u.is_first_login, u.online_status, u.last_active_time,
    u.create_time, u.update_time, u.create_by, u.update_by, u.remark,
    d.dept_name, p.post_name
FROM sys_user u
LEFT JOIN sys_dept d ON u.dept_id = d.id
LEFT JOIN sys_post p ON u.post_id = p.id

    u.deleted = 0

        AND u.username LIKE CONCAT('%', #{query.username}, '%')


        AND u.nickname LIKE CONCAT('%', #{query.nickname}, '%')


        AND u.email LIKE CONCAT('%', #{query.email}, '%')


        AND u.phone LIKE CONCAT('%', #{query.phone}, '%')


        AND u.status = #{query.status}


        AND u.dept_id = #{query.deptId}


        AND EXISTS (
            SELECT 1 FROM sys_user_role ur WHERE ur.user_id = u.id AND ur.role_id = #{query.roleId}
        )


        AND u.user_type = #{query.userType}


        AND u.online_status = #{query.onlineStatus}


        AND u.create_time >= #{query.startTime}


        AND u.create_time <= #{query.endTime}


ORDER BY u.create_time DESC

SELECT COUNT(*)
FROM sys_user u

    u.deleted = 0

        AND u.username LIKE CONCAT('%', #{query.username}, '%')


        AND u.nickname LIKE CONCAT('%', #{query.nickname}, '%')


        AND u.email LIKE CONCAT('%', #{query.email}, '%')


        AND u.phone LIKE CONCAT('%', #{query.phone}, '%')


        AND u.status = #{query.status}


        AND u.dept_id = #{query.deptId}


        AND EXISTS (
            SELECT 1 FROM sys_user_role ur WHERE ur.user_id = u.id AND ur.role_id = #{query.roleId}
        )


        AND u.user_type = #{query.userType}


        AND u.online_status = #{query.onlineStatus}


        AND u.create_time >= #{query.startTime}


        AND u.create_time <= #{query.endTime}
